- Use `nest new project-name` to create a new NestJS project.
- Update dependencies using `npm update`.
- Implement JWT authentication by installing `@nestjs/jwt` and `passport-jwt`.
- Configure JWT strategy in `auth.strategy.ts`:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { PassportStrategy } from '@nestjs/passport';
  import { ExtractJwt, Strategy } from 'passport-jwt';

  @Injectable()
  export class JwtStrategy extends PassportStrategy(Strategy) {
    constructor() {
      super({
        jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
        ignoreExpiration: false,
        secretOrKey: 'your-secret-key',
      });
    }

    async validate(payload: any) {
      return { userId: payload.sub, username: payload.username };
    }
  }
  ```
- Use guards for authentication in controllers:
  ```typescript
  import { Controller, Get, UseGuards } from '@nestjs/common';
  import { AuthGuard } from '@nestjs/passport';

  @Controller('profile')
  export class ProfileController {
    @Get()
    @UseGuards(AuthGuard('jwt'))
    getProfile() {
      return { message: 'This is a protected route' };
    }
  }
  ```
- Ensure sensitive fields are not exposed by stripping them from user objects:
  ```typescript
  const user = await this.userService.findOne(userId);
  delete user.password;
  return user;
  ```
- Use environment variables for secret keys and other sensitive information.
